#include <iostream>
#include <string>
#include <cctype>

using namespace std;

int main() {
    string s;
    cin >> s;

    string digits;
    for (char c : s) {
        if (isdigit(c)) {
            digits += c;
        }
    }

    int num = stoi(digits);
    cout << num * num << endl;

    return 0;
}
